package org.apache.commons.csv;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParse_withValidReader_returnsCSVParser() throws IOException {
        String csvData = "a,b,c\n1,2,3\n4,5,6";
        Reader reader = new StringReader(csvData);

        CSVParser parser = csvFormat.parse(reader);

        assertNotNull(parser);
        assertEquals(csvFormat, parser.getFormat());
    }

    @Test
    void testParse_withMockedReader_invokesCSVParserConstructor() throws IOException {
        Reader mockReader = mock(Reader.class);

        CSVParser parser = csvFormat.parse(mockReader);

        assertNotNull(parser);
        assertEquals(csvFormat, parser.getFormat());
    }

    @Test
    void testParse_throwsIOException_whenReaderThrows() {
        Reader failingReader = new Reader() {
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                throw new IOException("Forced IOException");
            }

            @Override
            public void close() throws IOException {
            }
        };

        assertThrows(IOException.class, () -> csvFormat.parse(failingReader));
    }
}
